const chatId  = $('Telegram Trigger').first().json.message.chat.id;

// Передаём публичный URL напрямую — OpenAI скачивает изображение сам.
// base64 не используем: n8n хранит бинарные данные на диске (filesystem-v2).
const planUrl = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/plans/' + chatId + '/plan.png?t=' + Date.now();

const prompt =
  'Ты — эксперт по анализу планов БТИ. Проанализируй план квартиры.\n' +
  'Верни ТОЛЬКО чистый JSON (без markdown, без пояснений) в точно таком формате:\n' +
  '{"rooms":[{"id":"room_1","name":"Жилая комната 1","region_percent":{"x1":0.05,"y1":0.10,"x2":0.45,"y2":0.55}}],' +
  '"shots":[{"shot_id":"room_1_shot_1","room_id":"room_1","room_name":"Жилая комната 1","position":"северо-западный угол","direction":"на юго-восток","instruction":"Встаньте в угол и сфотографируйте всё помещение целиком"}]}\n' +
  'Правила:\n' +
  '- Найди все помещения: жилые комнаты, кухня, санузел(ы), коридор, балкон/лоджия, кладовая\n' +
  '- Для каждого помещения: 1-2 точки съёмки (угол охвата >= 120 градусов)\n' +
  '- Инструкции конкретные: с какой точки, куда смотреть\n' +  '- Все тексты на русском языке\n' +
  '- region_percent: нормализованные координаты 0.0-1.0 всего изображения; 0,0 = верхний левый угол, 1,1 = нижний правый. Обводи точные границы каждого помещения по стенам';

const requestBody = {
  model: "gpt-4o-mini",
  messages: [{
    role: "user",
    content: [
      { type: "text", text: prompt },
      { type: "image_url", image_url: { url: planUrl, detail: "high" } }
    ]
  }],
  response_format: { type: "json_object" },
  temperature: 0.1,
  max_tokens: 4096
};

return [{ json: { chatId, requestBodyString: JSON.stringify(requestBody) } }];

const resp   = $input.first().json;
const chatId = $('Code - Gemini Request').first().json.chatId;

// API or HTTP error
if (resp.error || !resp.choices || !resp.choices[0]) {
  const msg = (resp.error && resp.error.message) || 'Ошибка API анализа плана';
  return [{ json: { error: true, chatId: chatId, errorMsg: msg } }];
}

let parsed;
try {
  const text = resp.choices[0].message.content;
  parsed = JSON.parse(text);
} catch(e) {
  return [{ json: { error: true, chatId: chatId,
    errorMsg: 'Не удалось распознать структуру плана. Попробуйте загрузить более чёткое изображение.' } }];
}

const rooms = parsed.rooms || [];
const shots = parsed.shots || [];

if (!shots.length) {
  return [{ json: { error: true, chatId: chatId,
    errorMsg: 'Не удалось определить комнаты на плане. Проверьте качество изображения и попробуйте снова.' } }];
}

const shotsStatus = {};
shots.forEach(function(s) { shotsStatus[s.shot_id] = 'pending'; });
const firstShot = shots[0];
shotsStatus[firstShot.shot_id] = 'requested';

function h(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

const roomsList = rooms.map(function(r) { return '\u2022 ' + h(r.name); }).join('\n');
const roomsText = '<b>\u041f\u043b\u0430\u043d \u043f\u0440\u043e\u0430\u043d\u0430\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d!</b>\n\u041e\u0431\u043d\u0430\u0440\u0443\u0436\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u043c\u0435\u0449\u0435\u043d\u0438\u044f:\n' + roomsList
  + '\n\u0412\u0441\u0435\u0433\u043e \u0442\u043e\u0447\u0435\u043a \u0441\u044a\u0451\u043c\u043a\u0438: ' + shots.length;

const total    = shots.length;
const firstMsg = '\uD83D\uDCF7 <b>\u0424\u043e\u0442\u043e 1 \u0438\u0437 ' + total + '</b>\n'
  + '\uD83C\uDFE0 ' + h(firstShot.room_name) + '\n'
  + '\uD83D\uDCCD \u041f\u043e\u0437\u0438\u0446\u0438\u044f: ' + h(firstShot.position) + '\n'
  + '\u27A1\uFE0F \u041d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435: ' + h(firstShot.direction) + '\n'
  + h(firstShot.instruction) + '\n'
  + '<i>\u041e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u0444\u043e\u0442\u043e \u043a\u0430\u043a \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442/\u0444\u0430\u0439\u043b \u2014 \u044d\u0442\u043e \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e</i>';

return [{ json: {
  error:             false,
  chatId:            chatId,
  rooms_json:        rooms,
  shots_json:        shots,
  shots_status:      shotsStatus,
  rooms_text:        roomsText,
  first_instruction: firstMsg,
  total_shots:       total
} }];

const session = $('Get a row1').first().json;
const chatId  = $('Telegram Trigger').first().json.message.chat.id;

const shotsStatus = typeof session.shots_status === 'string'
  ? JSON.parse(session.shots_status) : (session.shots_status || {});
const shots = typeof session.shots_json === 'string'
  ? JSON.parse(session.shots_json) : (session.shots_json || []);

const requestedShotId = Object.keys(shotsStatus).find(id => shotsStatus[id] === 'requested');
if (!requestedShotId) {
  throw new Error('Нет активной точки съёмки. Введите /start для перезапуска.');
}

const updatedStatus = { ...shotsStatus };
updatedStatus[requestedShotId] = 'received';

const nextShot = shots.find(s => updatedStatus[s.shot_id] === 'pending');
const allDone  = !nextShot;
let nextStatus = { ...updatedStatus };
let nextMessage = '';

// HTML-escape dynamic content from LLM
function h(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

if (!allDone) {
  nextStatus[nextShot.shot_id] = 'requested';
  const total     = shots.length;
  const shotIndex = shots.findIndex(s => s.shot_id === nextShot.shot_id) + 1;
  nextMessage = '📷 <b>Фото ' + shotIndex + ' из ' + total + '</b>\n\n'
    + '🏠 ' + h(nextShot.room_name) + '\n'
    + '📍 Позиция: ' + h(nextShot.position) + '\n'
    + '➡️ Направление: ' + h(nextShot.direction) + '\n\n'
    + h(nextShot.instruction) + '\n\n'
    + '<i>Отправьте фото как документ/файл — это сохраняет качество</i>';
} else {
  nextMessage = '✅ Все фотографии получены!\n\nНачинаю финальный анализ перепланировки. Это займёт 1-2 минуты...';
}

return [{
  json: {
    chatId,
    current_shot_id: requestedShotId,
    shots_status:    nextStatus,
    all_done:        allDone,
    next_message:    nextMessage,
    upload_path:     'photos/' + chatId + '/' + requestedShotId + '.jpg'
  },
  binary: items[0].binary
}];

// Binary data is received from HTTP Request - Download Plan node
// n8n stores binary as base64 in item.binary[key].data
const binary = $input.first().binary;
const key = Object.keys(binary)[0];
const base64 = binary[key].data;
const mimeType = binary[key].mimeType || 'image/jpeg';

if (!base64) throw new Error('Binary data is empty — plan not found in Supabase');

return [{ json: { base64, mimeType } }];

// Загрузи эти PDF в Supabase Storage: bti-files/knowledge-base/
// normy.pdf   → Чек лист нормы перепланировок
// katalog.pdf → Каталог типовых решений перепланировок
// razmery.pdf → Чек лист допустимые размеры помещений
return [
  { json: { path: 'knowledge-base/normy.pdf',   source: 'Чек лист нормы перепланировок' } },
  { json: { path: 'knowledge-base/katalog.pdf',  source: 'Каталог типовых решений перепланировок' } },
  { json: { path: 'knowledge-base/razmery.pdf',  source: 'Чек лист допустимые размеры помещений' } }
];

const resp   = $input.first().json;
const source = $('Code - PDF Sources').item?.json?.source || 'unknown';

let chunks = [];
try {
  // OpenAI: resp.choices[0].message.content
  const raw    = resp.choices?.[0]?.message?.content || '';
  const parsed = JSON.parse(raw);
  chunks = parsed.chunks || parsed.items || (Array.isArray(parsed) ? parsed : []);
} catch(e) {
  throw new Error('\u041e\u0448\u0438\u0431\u043a\u0430 \u043f\u0430\u0440\u0441\u0438\u043d\u0433\u0430 GPT: ' + e.message);
}

if (!chunks.length) throw new Error('GPT \u0432\u0435\u0440\u043d\u0443\u043b \u043f\u0443\u0441\u0442\u043e\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u0447\u0430\u043d\u043a\u043e\u0432 \u0434\u043b\u044f: ' + source);

return chunks.map((c, i) => ({
  json: {
    source,
    title: c.title || ('\u0411\u043b\u043e\u043a ' + (i + 1)),
    chunk: c.chunk || c.text || c.content || '',
    index: i
  }
}));

const embResp = $input.first().json;
// OpenAI embeddings: { data: [{ embedding: [...1536 floats...] }] }
const embedding = embResp.data?.[0]?.embedding;
if (!embedding) throw new Error('OpenAI \u043d\u0435 \u0432\u0435\u0440\u043d\u0443\u043b embedding: ' + JSON.stringify(embResp).substring(0, 200));

const chunkData = $('Code - Parse Chunks').item.json;

return [{
  json: {
    source:    chunkData.source,
    chunk:     chunkData.chunk,
    embedding: embedding
  }
}];

// Supabase REST returns the whole array as one item
var raw = $input.first().json;
var fragments = Array.isArray(raw) ? raw : $input.all().map(function(i) { return i.json; });

if (!fragments || fragments.length === 0) {
  return [{ json: { ragContext: '', fragmentCount: 0 } }];
}

var ragContext = fragments.map(function(f) { return f.chunk; }).join('\n---\n');
return [{ json: { ragContext: ragContext, fragmentCount: fragments.length } }];

var chatId = $('Telegram Trigger').first().json.message.chat.id;
var ragContext = $('Code - Format RAG Results').first().json.ragContext || '';
var session = $('Supabase - Get Analysis Session').first().json;
var planUrl = session.plan_url || '';
var shotsJson = session.shots_json
  ? (typeof session.shots_json === 'string' ? JSON.parse(session.shots_json) : session.shots_json)
  : [];
var shotsStatus = session.shots_status
  ? (typeof session.shots_status === 'string' ? JSON.parse(session.shots_status) : session.shots_status)
  : {};
var roomsJson = session.rooms_json
  ? (typeof session.rooms_json === 'string' ? JSON.parse(session.rooms_json) : session.rooms_json)
  : [];

var SUPABASE_STORAGE = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/photos/';

// Build list of received shots with room metadata (preserving order from shots_json)
var receivedShots = [];
for (var i = 0; i < shotsJson.length; i++) {
  var shot = shotsJson[i];
  var shotId = shot.shot_id || shot.id || '';
  var status = shotsStatus[shotId] || '';
  if (status === 'received' && shotId) {
    receivedShots.push({
      url: SUPABASE_STORAGE + chatId + '/' + shotId + '.jpg',
      room_id: shot.room_id || '',
      room_name: shot.room_name || '',
      position: shot.position || '',
      direction: shot.direction || ''
    });
  }
}

// Build room list from BTI plan analysis for GPT context
var roomsList = roomsJson.length > 0
  ? 'КОМНАТЫ НА ПЛАНЕ БТИ:\n' + roomsJson.map(function(r) {
      return '- room_id: ' + r.id + ', название: ' + r.name;
    }).join('\n')
  : '';

var systemPrompt = 'Ты — строгий технический инспектор БТИ с 20-летним опытом выявления незаконных перепланировок в России. ' +
  'Твоя задача — защитить жителей дома от последствий незаконных перепланировок. ' +
  'Будь педантичен: любое отклонение от плана БТИ должно быть зафиксировано. ' +
  'Лучше перестраховаться и указать requires_approval, чем пропустить нарушение. ' +
  'Отвечай только на русском языке. ' +
  'Всегда возвращай ответ строго в формате JSON без markdown-обёртки.';

var userText = 'НОРМАТИВЫ ИЗ БАЗЫ ЗНАНИЙ:\n' + ragContext + '\n\n---\n\n' +
  (roomsList ? roomsList + '\n\n---\n\n' : '') +
  'ЗАДАНИЕ:\n' +
  'Изображение 1 — официальный план БТИ квартиры.\n' +
  'Следующие изображения — фотографии реального состояния комнат (каждое предварено текстовой меткой с указанием комнаты).\n\n' +
  'ШАГ 1: Изучи план БТИ — запомни расположение стен, перегородок, дверных проёмов, санузлов, несущих конструкций.\n' +
  'ШАГ 2: Для каждой комнаты сравни реальное фото с соответствующей зоной на плане БТИ.\n' +
  'ШАГ 3: Зафиксируй любые отклонения: снос/перенос стен, замурованные/новые проёмы, объединение комнат, перенос мокрых зон, изменение площади.\n' +
  'ШАГ 4: Классифицируй каждое изменение по нормативам.\n\n' +
  'Формат ответа JSON:\n' +
  '{"confidence": <0-1>, "changes": [{"room_id": "...", "type": "...", "description": "...", "classification": "legal|requires_approval|illegal", "recommendation": "...", "change_region": {"x1": 0.0, "y1": 0.0, "x2": 1.0, "y2": 1.0}}], "summary": "..."}\n\n' +
  'Допустимые значения type: wall_removal, wall_addition, doorway_change, room_merge, room_split, wet_zone_move, other\n' +
  'ОБЯЗАТЕЛЬНОЕ поле change_region — координаты именно изменённого элемента на плане БТИ (не всей комнаты!), нормализованные 0.0-1.0. wall_removal/wall_addition: координаты линии стены (узкий вытянутый прямоугольник вдоль стены). doorway_change: только координаты проёма. room_merge: линия снесённой перегородки. wet_zone_move: новое место мокрой зоны. Не возвращай изменение без change_region.\n' +
  'Классификации: legal — разрешено без согласования, requires_approval — требует согласования, illegal — незаконно (несущие стены, мокрые зоны на жилую площадь, газ).\n' +
  'ВАЖНО: Если на фото видны отклонения от плана — фиксируй их, даже если не уверен на 100%. Используй requires_approval для спорных случаев.\n' +
  'КРИТИЧЕСКИ ВАЖНО: все поля JSON (description, recommendation, summary) пиши ИСКЛЮЧИТЕЛЬНО на русском языке.';

var contentArray = [{ type: 'text', text: userText }];
if (planUrl) {
  contentArray.push({ type: 'image_url', image_url: { url: planUrl, detail: 'high' } });
}
// Add each photo with a text label identifying the room
for (var j = 0; j < receivedShots.length; j++) {
  var s = receivedShots[j];
  var label = 'Фото ' + (j + 1) + ': комната ' + s.room_name + ' (room_id: ' + s.room_id + '), позиция: ' + s.position + ', направление: ' + s.direction;
  contentArray.push({ type: 'text', text: label });
  contentArray.push({ type: 'image_url', image_url: { url: s.url, detail: 'high' } });
}

var body = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: contentArray }
  ],
  max_tokens: 4000,
  response_format: { type: 'json_object' }
};

return [{ json: { chatId: chatId, body: JSON.stringify(body), photoCount: receivedShots.length } }];

var chatId = $('Code - Build GPT4o Payload').first().json.chatId;
var resp = $input.first().json;

// API or HTTP error
if (resp.error || !resp.choices || !resp.choices[0]) {
  return [{ json: { error: true, chatId: chatId,
    errorMsg: (resp.error && resp.error.message) || '\u041e\u0448\u0438\u0431\u043a\u0430 GPT-4o API' } }];
}

var responseContent = '';
try {
  responseContent = resp.choices[0].message.content;
} catch(e) {
  return [{ json: { error: true, chatId: chatId, errorMsg: '\u041e\u0448\u0438\u0431\u043a\u0430 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u044f \u043e\u0442\u0432\u0435\u0442\u0430: ' + e.message } }];
}

var analysisResult;
try {
  analysisResult = JSON.parse(responseContent);
} catch(e) {
  analysisResult = {
    confidence: 0,
    changes: [],
    summary: '\u041e\u0448\u0438\u0431\u043a\u0430 \u043f\u0430\u0440\u0441\u0438\u043d\u0433\u0430 GPT-4o: ' + responseContent.substring(0, 200)
  };
}

if (!analysisResult.changes)    { analysisResult.changes    = []; }
if (typeof analysisResult.confidence === 'undefined') { analysisResult.confidence = 0.5; }
if (!analysisResult.summary)    { analysisResult.summary    = ''; }

return [{ json: { error: false, chatId: chatId, analysis_result: analysisResult } }];

const msg = $('Telegram Trigger').first().json.message;
var fileId;
if (msg.document && msg.document.file_id) {
  fileId = msg.document.file_id;
} else if (msg.photo && msg.photo.length > 0) {
  fileId = msg.photo[msg.photo.length - 1].file_id;
} else {
  throw new Error('No file found in message: document=' + JSON.stringify(msg.document) + ' photo=' + JSON.stringify(msg.photo));
}
if (!fileId) {
  throw new Error('file_id is empty');
}
return [{ json: { file_id: fileId } }];

var ar = $('Code - Parse GPT4o Response').first().json.analysis_result;
var chatId = $('Code - Parse GPT4o Response').first().json.chatId;
var changes = ar.changes || [];
var confidence = typeof ar.confidence === 'number' ? ar.confidence : 0.5;
var summary = ar.summary || '';
var isLow = confidence < 0.6;
var pct = Math.round(confidence * 100);

function h(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function icon(cls) {
  if (cls === 'illegal') return '❌';
  if (cls === 'requires_approval') return '⚠️';
  return '✅';
}
function label(cls) {
  if (cls === 'illegal') return 'Незаконная перепланировка';
  if (cls === 'requires_approval') return 'Требует согласования';
  return 'Согласуемая';
}

var lines = changes.map(function(c, i) {
  return (i+1) + '. ' + icon(c.classification) + ' <b>' + h(label(c.classification)) + '</b>\n'
    + '   ' + h(c.description) + '\n'
    + '   <i>' + h(c.recommendation) + '</i>';
});

var report = '📊 <b>Результат анализа перепланировки</b>\n\n' + h(summary) + '\n\n';
if (lines.length > 0) {
  report += '<b>Обнаруженные изменения:</b>\n' + lines.join('\n\n') + '\n\n';
} else {
  report += 'Значимых изменений не обнаружено.\n\n';
}
if (isLow) {
  report += '⚠️ <i>Уверенность анализа: ' + pct + '%. Ваш запрос передан специалисту для ручной проверки.</i>\n\n';
}
report += '<i>⚠️ Результат носит информационный характер и не является юридическим заключением.</i>';

var managerMsg = '🔔 <b>Требуется ручная проверка</b>\n\n'
  + 'Chat ID: <code>' + chatId + '</code>\n'
  + 'Уверенность GPT-4o: ' + pct + '%\n\n'
  + '<b>Резюме:</b> ' + h(summary) + '\n'
  + 'Пожалуйста, проверьте анализ вручную.';

return [{ json: { chatId: chatId, report_text: report, manager_text: managerMsg,
                  confidence: confidence, is_low_confidence: isLow } }];

const chatId  = $('Telegram Trigger').first().json.message.chat.id;

// Передаём публичный URL напрямую — OpenAI скачивает изображение сам.
// base64 не используем: n8n хранит бинарные данные на диске (filesystem-v2).
const planUrl = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/plans/' + chatId + '/plan.png?t=' + Date.now();

const prompt =
  'Ты — эксперт по анализу планов БТИ. Проанализируй план квартиры.\n' +
  'Верни ТОЛЬКО чистый JSON (без markdown, без пояснений) в точно таком формате:\n' +
  '{"rooms":[{"id":"room_1","name":"Жилая комната 1","region_percent":{"x1":0.05,"y1":0.10,"x2":0.45,"y2":0.55}}],' +
  '"shots":[{"shot_id":"room_1_shot_1","room_id":"room_1","room_name":"Жилая комната 1","position":"северо-западный угол","direction":"на юго-восток","instruction":"Встаньте в угол и сфотографируйте всё помещение целиком"}]}\n' +
  'Правила:\n' +
