var changes = ar.changes || [];
var confidence = typeof ar.confidence === 'number' ? ar.confidence : 0.5;
var summary = ar.summary || '';
var isLow = confidence < 0.6;
var pct = Math.round(confidence * 100);

function h(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function icon(cls) {
  if (cls === 'illegal') return '❌';
  if (cls === 'requires_approval') return '⚠️';
  return '✅';
}
function label(cls) {
  if (cls === 'illegal') return 'Незаконная перепланировка';
  if (cls === 'requires_approval') return 'Требует согласования';
  return 'Согласуемая';
}

var lines = changes.map(function(c, i) {
  return (i+1) + '. ' + icon(c.classification) + ' <b>' + h(label(c.classification)) + '</b>\n'
    + '   ' + h(c.description) + '\n'
    + '   <i>' + h(c.recommendation) + '</i>';
});

var report = '📊 <b>Результат анализа перепланировки</b>\n\n' + h(summary) + '\n\n';
